export interface SkillLevel { level: number; sp?: number; cast?: number; cooldown?: number; range?: number; effect: string; }
export interface Skill { id: string; name: string; job: string; maxLevel: number; type: "Active"|"Passive"|"Toggle"; target?: string; element?: string; description: string; levels: SkillLevel[]; jobTier: 1 | 2; }
export interface Job { id: string; name: string; icon: string; }

